def test_register_project_records_git_repo_and_rejects_non_git_path(
    tmp_path: Path,
    capsys,
) -> None:
    repo_path = tmp_path / "subject-repo"
    repo_path.mkdir()
    subprocess.run(["git", "init"], cwd=repo_path, check=True, capture_output=True)
    non_git_path = tmp_path / "not-git"
    non_git_path.mkdir()

    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "register-project",
                "subject",
                "--path",
                str(repo_path),
                "--test-command",
                "python3 -m pytest -q",
            ]
        )
        == 0
    )
    output = capsys.readouterr().out
    assert "project_registered: subject" in output
    assert f"root_path: {repo_path.resolve()}" in output
    assert "default_test_command: python3 -m pytest -q" in output
    assert f"allowed_write_roots: {repo_path.resolve()}" in output

    storage = Storage(tmp_path / ".agent" / "state.db")
    project = storage.get_registered_project("subject")
    assert project.name == "subject"
    assert project.root_path == str(repo_path.resolve())
    assert project.default_test_command == "python3 -m pytest -q"
    assert project.allowed_write_roots == [str(repo_path.resolve())]
    assert project.created_at
    assert project.updated_at

    project_note = tmp_path / "projects" / "subject" / "project.md"
    assert project_note.exists()
    note = project_note.read_text(encoding="utf-8")
    assert "# Project subject" in note
    assert f"- root_path: {repo_path.resolve()}" in note
    assert "- default_test_command: python3 -m pytest -q" in note
    assert f"- allowed_write_roots: {repo_path.resolve()}" in note

    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "register-project",
                "broken",
                "--path",
                str(non_git_path),
                "--test-command",
                "true",
            ]
        )
        == 1
    )
    rejected_output = capsys.readouterr().out
    assert "project_registration_failed: path is not a git repository" in rejected_output
    assert storage.get_registered_project("broken") is None


def test_run_goal_with_worktree_isolation_captures_diff_and_proposes_commit_effect(
    tmp_path: Path,
    capsys,
) -> None:
    repo_path = tmp_path / "subject-repo"
    _init_git_repo(repo_path)
    test_command = (
        "python3 -c \"from pathlib import Path; "
        "text = Path('agent_output.txt').read_text(); "
        "assert text == 'hello\\\\n'; print(text)\""
    )
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "register-project",
                "subject",
                "--path",
                str(repo_path),
                "--test-command",
                test_command,
            ]
        )
        == 0
    )
    capsys.readouterr()

    command = (
        "python3 -c \"from pathlib import Path; "
        "Path('agent_output.txt').write_text('hello\\\\n')\""
    )
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "run-goal",
                "write a marker file",
                "--project",
                "subject",
                "--isolation",
                "worktree",
                "--command",
                command,
            ]
        )
        == 0
    )
    output = capsys.readouterr().out
    assert "coding_run: awaiting_approval" in output
    assert "effect_type: local_git_commit" in output
    assert "effect_status: awaiting_approval" in output
    assert "approval_id: approval_" in output

    storage = Storage(tmp_path / ".agent" / "state.db")
    worktree = storage.list_recent_worktree_records()[0]
    effect = storage.list_recent_effects()[0]
    approval = storage.list_pending_approvals()[0]
    task = storage.get_task(effect.task_id)

    assert worktree.project_id == "subject"
    assert worktree.run_id == effect.run_id
    assert worktree.task_id == effect.task_id
    assert worktree.base_commit
    assert worktree.branch_name.startswith("clankeros/")
    assert Path(worktree.worktree_path).exists()
    assert not (repo_path / "agent_output.txt").exists()
    assert (Path(worktree.worktree_path) / "agent_output.txt").read_text() == "hello\n"
    head = subprocess.run(
        ["git", "rev-parse", "HEAD"],
        cwd=worktree.worktree_path,
        check=True,
        capture_output=True,
        text=True,
    ).stdout.strip()
    assert head == worktree.base_commit

    assert effect.capability == "local_coding_agent"
    assert effect.effect_type == "local_git_commit"
    assert effect.status == "awaiting_approval"
    assert effect.required_approval_id == approval.id
    assert effect.committed_at is None
    assert "agent_output.txt" in effect.proposed_payload["changed_files"]
    assert task.status == "waiting_approval"

    evidence_dir = tmp_path / "runs" / effect.run_id / "evidence"
    assert (evidence_dir / "summary.md").exists()
    assert (evidence_dir / "worktree.json").exists()
    assert (evidence_dir / "commands.jsonl").exists()
    assert "agent_output.txt" in (evidence_dir / "diff.patch").read_text()
    assert "agent_output.txt" in (evidence_dir / "diff_summary.md").read_text()
    assert "hello" in (evidence_dir / "tests.txt").read_text()
    verification = json.loads((evidence_dir / "verification.json").read_text())
    assert verification["status"] == "passed"
    assert verification["policy"]["allowed_write_roots"] is True
    assert verification["tests"]["exit_code"] == 0
    assert json.loads((evidence_dir / "effect.json").read_text())["id"] == effect.id
    assert approval.id in (evidence_dir / "approval.md").read_text()

    dashboard_path = generate_static_dashboard(tmp_path)
    dashboard = dashboard_path.read_text(encoding="utf-8")
    assert "## Operator Cockpit" in dashboard
    assert "### Approval Inbox" in dashboard
    assert approval.id in dashboard
    assert "### Proposed Effects" in dashboard
    assert effect.id in dashboard
    assert "local_git_commit" in dashboard
    assert "### Verification Status" in dashboard
    assert "worktree_command" in dashboard


def test_commit_approved_creates_one_git_commit_after_approval_and_is_idempotent(
    tmp_path: Path,
    capsys,
) -> None:
    repo_path = tmp_path / "subject-repo"
    _init_git_repo(repo_path)
    test_command = (
        "python3 -c \"from pathlib import Path; "
        "text = Path('agent_output.txt').read_text(); "
        "assert text == 'hello\\\\n'\""
    )
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "register-project",
                "subject",
                "--path",
                str(repo_path),
                "--test-command",
                test_command,
            ]
        )
        == 0
    )
    capsys.readouterr()

    command = (
        "python3 -c \"from pathlib import Path; "
        "Path('agent_output.txt').write_text('hello\\\\n')\""
    )
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "run-goal",
                "write a marker file",
                "--project",
                "subject",
                "--isolation",
                "worktree",
                "--command",
                command,
            ]
        )
        == 0
    )
    capsys.readouterr()

    storage = Storage(tmp_path / ".agent" / "state.db")
    effect = storage.list_recent_effects()[0]
    approval = storage.list_pending_approvals()[0]
    worktree_path = Path(effect.proposed_payload["worktree_path"])
    base_commit = effect.proposed_payload["base_commit"]

    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "approve",
                approval.id,
                "--decided-by",
                "operator",
                "--note",
                "reviewed",
            ]
        )
        == 0
    )
    capsys.readouterr()

    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "commit-approved",
                approval.id,
                "--committed-by",
                "operator",
            ]
        )
        == 0
    )
    output = capsys.readouterr().out
    assert "commit_approved: committed" in output
    assert f"effect_id: {effect.id}" in output
    assert "commit: " in output
    assert "evidence: " in output

    head = subprocess.run(
        ["git", "rev-parse", "HEAD"],
        cwd=worktree_path,
        check=True,
        capture_output=True,
        text=True,
    ).stdout.strip()
    assert head != base_commit
    commit_count = subprocess.run(
        ["git", "rev-list", "--count", "HEAD"],
        cwd=worktree_path,
        check=True,
        capture_output=True,
        text=True,
    ).stdout.strip()
    assert commit_count == "2"
    message = subprocess.run(
        ["git", "log", "-1", "--pretty=%B"],
        cwd=worktree_path,
        check=True,
        capture_output=True,
        text=True,
    ).stdout
    assert effect.id in message
    assert "agent_output.txt" in subprocess.run(
        ["git", "show", "--name-only", "--pretty=", "HEAD"],
        cwd=worktree_path,
        check=True,
        capture_output=True,
        text=True,
    ).stdout
    assert not (repo_path / "agent_output.txt").exists()

    updated_effect = storage.list_recent_effects()[0]
    assert updated_effect.status == "committed"
    assert updated_effect.committed_at is not None
    assert updated_effect.result_json["commit_sha"] == head
    assert updated_effect.result_json["approval_id"] == approval.id
    assert updated_effect.compensation_plan["command"] == f"git revert {head}"
    commit_evidence = Path(updated_effect.evidence_path).parent / "commit-approved.json"
    assert json.loads(commit_evidence.read_text(encoding="utf-8"))["commit_sha"] == head

    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "commit-approved",
                approval.id,
                "--committed-by",
                "operator",
            ]
        )
        == 0
    )
    repeat_output = capsys.readouterr().out
    assert "commit_approved: already_committed" in repeat_output
    assert head in repeat_output
    repeat_count = subprocess.run(
        ["git", "rev-list", "--count", "HEAD"],
        cwd=worktree_path,
        check=True,
        capture_output=True,
        text=True,
    ).stdout.strip()
    assert repeat_count == commit_count


def test_commit_approved_blocks_stale_evidence_without_creating_commit(
    tmp_path: Path,
    capsys,
) -> None:
    repo_path = tmp_path / "subject-repo"
    _init_git_repo(repo_path)
    test_command = (
        "python3 -c \"from pathlib import Path; "
        "text = Path('agent_output.txt').read_text(); "
        "assert text == 'hello\\\\n'\""
    )
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "register-project",
                "subject",
                "--path",
                str(repo_path),
                "--test-command",
                test_command,
            ]
        )
        == 0
    )
    capsys.readouterr()
    command = (
        "python3 -c \"from pathlib import Path; "
        "Path('agent_output.txt').write_text('hello\\\\n')\""
    )
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "run-goal",
                "write a marker file",
                "--project",
                "subject",
                "--isolation",
                "worktree",
                "--command",
                command,
            ]
        )
        == 0
    )
    capsys.readouterr()

    storage = Storage(tmp_path / ".agent" / "state.db")
    effect = storage.list_recent_effects()[0]
    approval = storage.list_pending_approvals()[0]
    worktree_path = Path(effect.proposed_payload["worktree_path"])
    base_commit = effect.proposed_payload["base_commit"]

    assert main(["--root", str(tmp_path), "approve", approval.id]) == 0
    capsys.readouterr()

    (worktree_path / "agent_output.txt").write_text("drifted\n", encoding="utf-8")
    assert (
        main(
            [
                "--root",
                str(tmp_path),
                "commit-approved",
                approval.id,
                "--committed-by",
                "operator",
            ]
        )
        == 1
    )
    output = capsys.readouterr().out
    assert "commit_approved_failed: stale evidence" in output
    assert "diff.patch" in output

    head = subprocess.run(
        ["git", "rev-parse", "HEAD"],
        cwd=worktree_path,
        check=True,
        capture_output=True,
        text=True,
    ).stdout.strip()
    assert head == base_commit
    updated_effect = storage.list_recent_effects()[0]
    assert updated_effect.status == "blocked"
    assert updated_effect.committed_at is None
    assert updated_effect.result_json["status"] == "blocked"
